    {
      "字段": "是否使用情绪放大（Agitate）",
      "解析": "是；用“惨不忍睹”等词强化负面情绪"
    },
    {
      "字段": "Feature 是否转化为 Benefit",
      "解析": "是；将“说”转化为“听得懂、愿意听、听完想行动”"
    },
    {
      "字段": "是否通过场景而非参数说服",
      "解析": "是；用“写作文”的方式来说明问题"
    }
  ],
  "五、信任与风险处理": [
    {
      "字段": "社会认同",
      "解析": "否；没有提及他人评价或数据支持"
    },
    {
      "字段": "权威背书",
      "解析": "否；没有引用专家或机构认证"
    },
    {
      "字段": "风险逆转",
